```c
/* linked_list.c ----------------------------------------------------------- */
#include "linked_list.h"

/*--------------------------------------------------------------
 * Helper: abort on out‑of‑memory with a clear message.
 * In production you may replace this with a more graceful
 * recovery strategy (e.g., returning NULL to the caller).
 *--------------------------------------------------------------*/
static void *checked_malloc(size_t n)
{
    void *p = malloc(n);
    if (p == NULL) {
        /* Fail fast – prevents undefined behaviour later */
        abort();               /* <--- CWE‑388: Error handling */
    }
    return p;
}

/*--------------------------------------------------------------
 * createLinkedList
 *   - Allocates the container.
 *   - Guarantees that the returned pointer is never NULL.
 *   - Initializes all fields to a known safe state.
 *--------------------------------------------------------------*/
LinkedList *createLinkedList(void)
{
    LinkedList *list = (LinkedList *)checked_malloc(sizeof(LinkedList));
    list->head = NULL;
    list->size = 0;
    return list;
}

/*--------------------------------------------------------------
 * isEmpty
 *   - Defensive: validates the input pointer before dereferencing.
 *   - Returns true when the list pointer is NULL *or* when the list
 *     contains no elements.  This choice avoids a crash if the
 *     caller mistakenly passes a NULL pointer.
 *--------------------------------------------------------------*/
bool isEmpty(const LinkedList *list)
{
    if (list == NULL) {
        /* Defensive default – treat a NULL list as empty.
         * Alternative: set errno/EINVAL and return false. */
        return true;
    }
    return (list->size == 0);
}

/*--------------------------------------------------------------
 * destroyLinkedList
 *   - Walks the list, frees each node, then frees the container.
 *   - Safe against double‑free and NULL arguments.
 *--------------------------------------------------------------*/
void destroyLinkedList(LinkedList *list)
{
    if (list == NULL) {
        return;   /* Nothing to do */
    }

    Node *cur = list->head;
    while (cur != NULL) {
        Node *next = cur->next;
        free(cur);
        cur = next;
    }

    /* Finally free the list structure itself */
    free(list);
}
```

